        ('REN_linear',      'linha_de_agua',                3, 'ecological',     10, 'geom', 'DL 166/2008 art. 20 (am. DL 124/2019)',                      TRUE,  'CCDR'),
        ('IC',              'monumento',                    3, 'heritage',       0,  'geom', 'Lei 107/2001 art. 45 + DL 309/2009',                         TRUE,  'DGPC / Direcao Regional de Cultura'),
