        ('RedeFerroviaria', 'servidao_ferroviaria_estacao', 3, 'infrastructure', 10, 'geom', 'DL 276/2003 art. 15',                                        TRUE,  'Infraestruturas de Portugal'),
        ('Albufeiras',      'protegida',                    3, 'water_domain',   0,  'geom', 'DL 107/2009 art. 21',                                        TRUE,  'APA / ARH'),
