        ('Albufeiras',      'livre',                        2, 'water_domain',   0,  'geom', 'DL 107/2009 art. 19',                                        TRUE,  'APA / ARH'),
        ('DefesaMilitar',   'nucleo',                       3, 'military',       0,  'geom', 'Lei 2078/1955 + DL 45986/1964',                              TRUE,  'Ministerio da Defesa Nacional'),
